import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMovies, exportM3U } from '../../services/api';

const AdminPanel = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [exporting, setExporting] = useState(false);

  useEffect(() => {
    loadMovies();
  }, []);

  const loadMovies = async () => {
    try {
      const data = await getMovies();
      setMovies(data);
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleExportM3U = async () => {
    setExporting(true);
    try {
      const response = await exportM3U();

      // Crear archivo para descarga
      const blob = new Blob([response], { type: 'text/plain' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'raulflix_playlist.m3u';
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(url);
    } catch (error) {
      alert('Error al exportar: ' + error.message);
    } finally {
      setExporting(false);
    }
  };

  if (loading) return <div className="p-8">Cargando...</div>;

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-bold">Panel de Administración</h1>
        <div className="space-x-4">
          <Link 
            to="/admin/add-movie" 
            className="bg-green-600 hover:bg-green-700 px-4 py-2 rounded"
          >
            Agregar Película
          </Link>
          <Link 
            to="/admin/add-series" 
            className="bg-purple-600 hover:bg-purple-700 px-4 py-2 rounded"
          >
            Agregar Serie
          </Link>
          <button
            onClick={handleExportM3U}
            disabled={exporting || movies.length === 0}
            className="bg-blue-600 hover:bg-blue-700 disabled:bg-gray-600 px-4 py-2 rounded"
          >
            {exporting ? 'Exportando...' : 'Exportar M3U'}
          </button>
        </div>
      </div>

      <div className="bg-gray-800 rounded-lg overflow-hidden">
        <div className="p-4 bg-gray-700">
          <h2 className="text-xl font-semibold">Películas ({movies.length})</h2>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-700">
              <tr>
                <th className="p-3 text-left">Título</th>
                <th className="p-3 text-left">Tipo</th>
                <th className="p-3 text-left">Año</th>
                <th className="p-3 text-left">Géneros</th>
                <th className="p-3 text-left">Estado</th>
                <th className="p-3 text-left">Acciones</th>
              </tr>
            </thead>
            <tbody>
              {movies.map(movie => (
                <tr key={movie.id} className="border-t border-gray-700">
                  <td className="p-3">
                    <div className="flex items-center">
                      <img 
                        src={movie.poster || 'https://via.placeholder.com/48x64/374151/9CA3AF?text=Sin+Imagen'} 
                        alt={movie.title}
                        className="w-12 h-16 object-cover rounded mr-3"
                        onError={(e) => {
                          e.target.src = 'https://via.placeholder.com/48x64/374151/9CA3AF?text=Sin+Imagen';
                        }}
                      />
                      <span className="font-medium">{movie.title}</span>
                    </div>
                  </td>
                  <td className="p-3">
                    <span className={`px-2 py-1 rounded text-xs ${
                      movie.type === 'series' ? 'bg-purple-600' : 'bg-blue-600'
                    }`}>
                      {movie.type === 'series' ? 'Serie' : 'Película'}
                    </span>
                  </td>
                  <td className="p-3">{movie.year}</td>
                  <td className="p-3">
                    <div className="flex flex-wrap gap-1">
                      {movie.genre.slice(0, 2).map(g => (
                        <span key={g} className="bg-gray-600 px-2 py-1 rounded text-xs">
                          {g}
                        </span>
                      ))}
                      {movie.genre.length > 2 && (
                        <span className="text-gray-400 text-xs">+{movie.genre.length - 2}</span>
                      )}
                    </div>
                  </td>
                  <td className="p-3">
                    <span className={`px-2 py-1 rounded text-xs ${
                      movie.streams?.some(s => s.active) ? 'bg-green-600' : 'bg-red-600'
                    }`}>
                      {movie.streams?.some(s => s.active) ? 'Activo' : 'Inactivo'}
                    </span>
                  </td>
                  <td className="p-3">
                    <div className="flex gap-2">
                      <Link
                        to={movie.type === 'series' ? `/admin/edit-series/${movie.id}` : `/admin/edit-movie/${movie.id}`}
                        className="bg-yellow-600 hover:bg-yellow-700 px-2 py-1 rounded text-xs"
                      >
                        Editar
                      </Link>
                      <button
                        onClick={() => handleDelete(movie.id)}
                        className="bg-red-600 hover:bg-red-700 px-2 py-1 rounded text-xs"
                      >
                        Eliminar
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;
